//import YYModel

// MARK: - 常量
public let kCCCProtocolTypeKey      = "CCC"
public let kICCOAProtocolTypeKey    = "ICCOA"
public let kICCEProtocolTypeKey     = "ICCE"
public let kXPBLEProtocolTypeKey    = "XPBLE"

public let kPhoneDeviceTypeKey      = "PHONE"
public let kWatchDeviceTypeKey      = "WATCH"
public let kAppletDeviceTypeKey     = "APPLET"
public let kOtherDeviceTypeKey      = "OTHER"

// MARK: - 枚举
@objc(XPBLEKeyCardStatus)
public enum BleKeyCardStatus: Int, Codable, SQLSpecificExpressible {
    case invalid        = 0  // 已失效
    case normal         = 1  // 正常
    case toBeActivated  = 2  // 待激活
    case activated      = 3  // 激活生效中
    case reportingLost  = 4  // 挂失生效中
    case reportLost     = 5  // 已挂失
    case reportingFound = 6  // 解挂生效中
    case locking        = 7  // 锁定生效中
    case locked         = 8  // 已锁定
    case unlocking      = 9  // 解锁生效中
    case blacking       = 10 // 加黑生效中
    case blacked        = 11 // 已加黑
    case unblacking     = 12 // 解黑生效中
    case removeing      = 13 // 注销生效中
    case expired        = 14 // 已过期
    case preCreated     = 15 // 预创建
}

@objc(XPBLEKeyCardType)
public enum BleKeyCardType: Int, Codable, SQLSpecificExpressible {
    case _BLEKey             = 101
    case _BLECertKey         = 102
    case _BLESelfKey         = 103
    case _BLEWatchKey        = 104
    case _WatchCertKey       = 105
    case _BLEMonaKey         = 106
    case _NFCCardKey         = 201
    case _NFCPhoneKey        = 202
    case _NFCWatchKey        = 203
    case _V3_XPBLE_PhoneKey  = 301
    case _V3_XPBLE_AppletKey = 303
    case _V3_Phone_CCCKey    = 304
    case _V3_XPBLE_OtherKey  = 305
    case _V3_Phone_ICCOAKey  = 306
    case _V3_Watch_CCCKey    = 307
    case _V3_Phone_ICCEKey   = 308
}

@objc public enum KeyCardOperationType: Int {
    case add    = 1
    case modify = 2
    case delete = 3
}

fileprivate let tag = "[BleKeyCard]"

// MARK: - 模型
@objc(XPBLEKeyCard)
public final class BleKeyCard: NSObject, DBClientRecord {

    @objc public var cardNo: String = ""
    @objc public var status: BleKeyCardStatus = .normal
    @objc public var nickName: String?
    @objc public var effectiveTime: UInt64 = 0
    @objc public var validTime: UInt64 = 0
    @objc public var cardType: BleKeyCardType = ._BLEKey
    @objc public var deviceId: String?
    @objc public var shareFrom: String?
    @objc public var vin: String?
    @objc public var color: String?
    @objc public var plateNo: String?
    @objc public var model: String?
    @objc public var tel: String?
    @objc public var reason: String?
    @objc public var uid: UInt64 = 0
    @objc @DefaultFalse public var isRegisterInThisInstall: Bool
//    @objc public var isRegisterInThisInstall: Bool = false
    @objc public var createTime: UInt64 = 0
    @objc public var updateTime: UInt64 = 0
    @objc public var macAddr: String?
    @objc public var surportUWB: UInt64 = 0
    @objc public var isInCache: Bool = false

    // readonly
    @objc public var invalidTime: Int64 { Int64(validTime) * 60 * 1000 }
    @objc public var effectiveDate: Date { Date(timeIntervalSince1970: TimeInterval(effectiveTime) * 60) }
    @objc public var validDate: Date? { validTime == 0 ? nil : Date(timeIntervalSince1970: TimeInterval(invalidTime) / 1000) }
    @objc public var createDate: Date { Date(timeIntervalSince1970: TimeInterval(createTime) / 1000) }
    @objc public var updateDate: Date { Date(timeIntervalSince1970: TimeInterval(updateTime) / 1000) }
    @objc public var ssid: String {
        guard let mac = macAddr, !mac.isEmpty else { return "" }
        return "XPED-" + mac.replacingOccurrences(of: ":", with: "").uppercased()
    }

    // MARK: - GRDB
    public static var databaseTableName: String { "xpblekeycard" }

    public enum CodingKeys: String, CodingKey {
        case cardNo                    // 卡号
        case status                    // 状态
        case nickName                  // 昵称
        case effectiveTime             // 生效时间
        case validTime                 // 有效时间
        case cardType                  // 卡片类型
        case deviceId                  // 设备ID
        case shareFrom                 // 分享来源
        case vin                       // 车辆VIN码
        case color                     // 颜色
        case plateNo                   // 车牌号
        case model                     // 车型
        case tel                       // 电话
        case reason                    // 原因
        case uid                       // 用户ID
        case isRegisterInThisInstall   // 是否在当前安装中注册
        case createTime                // 创建时间
        case updateTime                // 更新时间
        case macAddr                   // MAC地址
    }

    // 定义Columns结构体，用于类型安全的列名
    public enum Columns {
        public static let cardNo                  = Column(CodingKeys.cardNo.rawValue)
