    public static func createTableIfNeeded(_ db: Database) throws {
        BBLog.info(tag: tag, "BleKeyCard createTableIfNeeded")
        // 创建表在 migratorIfNeeded 中统一处理
    }

    public static func migratorIfNeeded(_ migrator: DatabaseMigrator) throws -> DatabaseMigrator {
        var migrator = migrator
        BBLog.info(tag: tag, "BleKeyCard migratorIfNeeded")

        // 这里的版本号不要跟其他表的版本号冲突
        migrator.registerMigration("\(databaseTableName)_1.0.0") { db in
            BBLog.info(tag: tag, "BleKeyCard 旧数据库迁移，删除旧表 -> 创建新表 （WCDB数据库初次升级到GRDB）")

            let list: [BleKeyCard] = {
                do {
                    return try BleKeyCard.fetchAll(db)
                } catch {
                    BBLog.info(tag: tag, "fetchAll failed: $error)") // 可选：记录日志
                    return []
                }
            }()

            if (try db.tableExists(databaseTableName)) {
                try db.drop(table: databaseTableName)
            }

            try db.create(
                table: databaseTableName,
                ifNotExists: true) { table in
                    table.column(Columns.cardNo.name, .text).primaryKey(onConflict: .replace)
                    table.column(Columns.status.name, .integer).notNull().defaults(to: 1)
                    table.column(Columns.nickName.name, .text)
                    table.column(Columns.effectiveTime.name, .integer).notNull().defaults(to: 0)
                    table.column(Columns.validTime.name, .integer).notNull().defaults(to: 0)
                    table.column(Columns.cardType.name, .integer).notNull().defaults(to: 101)
                    table.column(Columns.deviceId.name, .text)
                    table.column(Columns.shareFrom.name, .text)
                    table.column(Columns.vin.name, .text)
                    table.column(Columns.color.name, .text)
                    table.column(Columns.plateNo.name, .text)
                    table.column(Columns.model.name, .text)
                    table.column(Columns.tel.name, .text)
                    table.column(Columns.reason.name, .text)
                    table.column(Columns.uid.name, .integer).notNull().defaults(to: 0)
                    table.column(Columns.isRegisterInThisInstall.name, .boolean).notNull().defaults(to: false)
                    table.column(Columns.createTime.name, .integer).notNull().defaults(to: 0)
                    table.column(Columns.updateTime.name, .integer).notNull().defaults(to: 0)
                    table.column(Columns.macAddr.name, .text)
                }

            for item in list {
                try item.insert(db)
            }
        }

        // 下次数据表升级时开启以下代码
//        migrator.registerMigration("\(databaseTableName)_1.0.1") { db in
//            BBLog.info("BleKeyCard 表结构变化，数据库迁移，新增字段")
//            try db.alter(table: "\(databaseTableName)") { t in
//                t.add(column: "age", .integer)
//            }
//        }

        return migrator
    }
}

