        let isSDK2ndCar = XPVehicleSDK.shared.vehicleManager.isOpenedVehicleTypeCode(XPDBProxyHelper.shared.dbMessageProxy?.currentVehicleTypeCode() ?? "")

        if isSDK2ndCar {
            return XPVehicleSDK.currentVehicle()?.digitalKeyManager?.digitalKey(keyCardType: .SAFE) != nil
        }

        return isCreateInThisDevice() && isRegisterInThisInstall && (status == .normal || status == .activated)
    }

