//                }
//            }

            let allCards = try XPDBManager.client.read { db in
                try BleKeyCard
                    .filter(vins.contains(Columns.vin))
                    .fetchAll(db)
            }
            let allVins = allCards?.map { $0.vin } ?? []
            let toDelete = Set(allVins).subtracting(Set(vins))
            for vin in toDelete {
                BBLog.info(tag: tag, "待删除钥匙数据的vin: \(vin)")
                if let vin = vin {
                    deleteAllCards(vin: vin)
                }
            }
            if toDelete.isEmpty {
                BBLog.info(tag: tag, "无需同步证书钥匙报文数据")
            }
        } catch {
