extension BleKeyCard {
    @objc public static func modelCustomPropertyMapper() -> [String : Any]? {
        [
            "effectiveTime": "effectiveTime",
            "vin":           "vin",
            "cardNo":        "cardNo",
            "createTime":    "createTime",
            "cardType":      "cardType",
            "nickName":      "nickName",
            "validTime":     "validTime",
            "shareFrom":     "shareFrom",
            "status":        "status",
            "updateTime":    "updateTime",
            "tel":           "tel",
            "reason":        "reason"
        ]
    }

    @objc public func modelCustomTransform(from dic: [AnyHashable : Any]) -> Bool {
        // uid
        let userId = (dic["userId"] as? NSNumber)?.uint64Value ?? 0
        uid = userId == 0 ? XPVehicleSDK.shared.vehicleManager.uid : userId

        // keyId -> cardNo
        if let keyId = dic["keyId"] as? String, !keyId.isEmpty {
            cardNo = keyId
        }

        // keyName -> nickName
        if let keyName = dic["keyName"] as? String, !keyName.isEmpty {
            nickName = keyName
        }

        // phoneType -> model
        if let phoneType = dic["phoneType"] as? String, !phoneType.isEmpty {
            model = phoneType
        }

        // protocolType + deviceType -> cardType
        if let protocolType = dic["protocolType"] as? String,
           let deviceType   = dic["deviceType"]   as? String,
           !protocolType.isEmpty,
           !deviceType.isEmpty {

            switch protocolType {
            case kXPBLEProtocolTypeKey:
                switch deviceType {
                case kPhoneDeviceTypeKey:
                    cardType = ._BLESelfKey
                case kWatchDeviceTypeKey:
                    cardType = ._WatchCertKey
                case kAppletDeviceTypeKey:
                    cardType = ._V3_XPBLE_AppletKey
                default:
                    cardType = ._V3_XPBLE_OtherKey
                }
            case kCCCProtocolTypeKey:
                if deviceType == kPhoneDeviceTypeKey  { cardType = ._V3_Phone_CCCKey  }
                if deviceType == kWatchDeviceTypeKey  { cardType = ._V3_Watch_CCCKey  }
            case kICCOAProtocolTypeKey:
                cardType = ._V3_Phone_ICCOAKey
            case kICCEProtocolTypeKey:
                cardType = ._V3_Phone_ICCEKey
            default: break
            }
        }

        // keyType -> shareFrom
        if let keyType = dic["keyType"] as? String, keyType == "OWNER" {
            shareFrom = "0"
        } else {
            if shareFrom != "0" { shareFrom = "SHARED" }
        }

        // keyStatus -> status
        if let keyStatus = dic["keyStatus"] as? Int {
            status = BleKeyCardStatus(rawValue: keyStatus) ?? .normal
        }

        // 日期解析 yyyy-MM-dd HH:mm:ss
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyy-MM-dd HH:mm:ss"

        if let start = dic["keyValidStart"] as? String,
           let date = formatter.date(from: start) {
            effectiveTime = UInt64(date.timeIntervalSince1970)
        }

        if let end = dic["keyValidEnd"] as? String,
           let date = formatter.date(from: end) {
            validTime = UInt64(date.timeIntervalSince1970)
        }

        // keyCapability -> surportUWB
        if let capability = dic["keyCapability"] as? [String: Any],
           let uwb = capability["uwb"] as? NSNumber {
            surportUWB = uwb.uint64Value
        }
        return true
    }
}

