//
//  BLESelfKeyHandler.swift
//  XPVehicleSDK
//
//  Created by huzy2 on 2024/11/28.
//

import Foundation

open class BLESelfKeyHandler : BLEHandler {
    var device: BleDevice
    var deviceUUid: String {
        device.name
    }
    var connectStartTime: CFAbsoluteTime = 0
    var connectSuccessTime: CFAbsoluteTime = 0

    init(ssidPrefix: String, name: String, macAddress: String, dataParser: BLEKeyParserProtocol, useScanUUIDs: Bool, useRssiNotify: Bool) {
        Log.i("蓝牙 BLEHandler.init mac:", macAddress, " name:", name)
        self.device = BleDevice(ssidPrefix: ssidPrefix, macAddress: macAddress, useScanUUIDs: useScanUUIDs, useRssiNotify: useRssiNotify)
        super.init(ssidPrefix: ssidPrefix, name: name, macAddress: macAddress, dataParser: dataParser)
        addDeviceObserver()
    }

    override func connect() {
        super.connect()
        guard self.device.state == .NotConnected else { return }
        self.device.connect()
    }

    override func disconnect() {
        super.disconnect()
        guard self.device.state != .NotConnected else { return }
        self.state = .NotConnected
        device.disconnect()
    }

    override func exitBleRetrieveCache() -> Bool {
        return device.exitBleRetrieveCache()
    }

    override func startAuth() {
        Log.i("蓝牙 开始启动鉴权流程")
        let startTime = CFAbsoluteTimeGetCurrent()
        let macAddress = self.macAddress
        self.authFlowCancellable = self.bleAuthFlow?.startFlow().timeout(.seconds(5.0), scheduler: DispatchQueue.global(qos: .userInteractive),customError: { BleAuthError.timeout }).sink { [weak self] completion in
            switch(completion) {
            case .finished:
                Log.i("蓝牙 鉴权流程成功 finished")
                let currTime = CFAbsoluteTimeGetCurrent()
                Log.i("[鉴权成功]蓝牙 鉴权流程 耗时:(\(String(format:"%.03f", currTime - startTime))秒)")
                self?.trackAuthSuccess(duration: Int64((currTime - startTime) * 1000), step: self?.bleAuthFlow?.authStep ?? 2)
                // TODO: 需要将 [Data] 传递给BLE数据解析器
                self?.bleAuthFlow = nil
                if (self?.device.state ?? .NotConnected) == .Available {
                    Log.i("[鉴权成功]蓝牙 鉴权流程 检查蓝牙状态成功")
                    self?.state = .Available
                }
            case .failure(let error):
                let currTime = CFAbsoluteTimeGetCurrent()
                if (error == BleAuthError.timeout) {
                    Log.i("蓝牙 鉴权流程结束 .failure 鉴权超时")
                } else {
                    Log.i("蓝牙 鉴权流程结束 .failure Received error: \(error.description)")
                }

                self?.trackAuthFaile(duration: Int64((currTime - startTime) * 1000), step: self?.bleAuthFlow?.authStep ?? 2, error: error)
                self?.bleAuthFlow = nil
                self?.state = .NotConnected
                self?.device.disconnect()
                NotificationCenter.default.post(name: VehicleNotification.BleConnectError, object: nil, userInfo: ["error": BLEConnectErrorNotiObject(macAddress: macAddress, errorState: .authFailue)])
            }
        } receiveValue: {
        }
    }

    override func cleanBleInfoCache() {
        super.cleanBleInfoCache()
        device.cleanBleInfoCache()
    }

    override func send(data: BleSendData, success: SuccessCallback?, failed: FailedCallback?) {
        guard state == .Available else {
            failed?(BleDeviceError.bleNotConnect)
            return
        }

        self.device.bleSendFlow.write(params: data, success: success, failed: failed)
    }

    override func readRssi() {
        device.readRssi()
    }

    func addDeviceObserver() {
        self.device.statePublisher.dropFirst().sink {[weak self] state in
            Log.i("\(self?.name ?? "")蓝牙连接状态：", state)
            if (self?.state != state) {
                if (state == .Available) {
                    Log.i(tag:"BLE", "\(self?.name ?? "")蓝牙连接成功，开始鉴权")
                    self?.connectSuccessTime = CFAbsoluteTimeGetCurrent()
                    self?.trackBleConnectSuccess()
                    self?.trackStartAuth()
                    self?.startAuth()
                } else {
                    self?.state = state
                    if (state == .NotConnected) {
                        Log.i(tag:"BLE", "\(self?.name ?? "")蓝牙连接失败")
                        self?.cancelAuthIfneed()
                    }
                    if (state == .Scanning) {
                        self?.connectStartTime = CFAbsoluteTimeGetCurrent()
                    }
                }
            }
        }
        .store(in: &cancellables)

        self.device.recieveNotify =  { [weak self] data in
            Log.i("蓝牙BLE 收到数据 data[\(data?.count ?? 0)]: ", data?.toHexString() ?? "nil")
            guard let data = data else {
                return
            }
            self?.dataParser.parseBleData(data)
        }

        self.device.recieveRssiNotify =  { [weak self] data in
            guard let data = data else {
                return
            }
            if let parser = self?.dataParser as? BLERssiDataParserProtocol {
                parser.parseBleRssiData(data,deviceUUid: self?.deviceUUid ?? "")
            } else {
                print("Unknown parser type")
            }
        }

        device.sendDataFullSubject.sink {[weak self] count in
            Statistics.trackingBleSendDataFull(operation_count: count, model: self?.statisticsModel)
        }.store(in: &cancellables)


        device.sendNoCacheSubject.sink {[weak self] action in
            self?.trackNoCache(action: action)
        }.store(in: &cancellables)
    }
}

