import Foundation

public class CarKeyConditionCheck {

    public static func isSupportCarKeySoftware(cccVid: String?, bleKeyVersion: Int, isSupportCCC: Bool) -> Bool {
        if #available(iOS 18.0, *) {
            if cccVid == nil {
                return false
            }
            if bleKeyVersion != BleKeyProtocolVesion.V3.rawValue {
                return false
            }
            if CarKeyPassAccesser.supportCarKeyType() == .none {
                return false
            }
            return isSupportCCC
        } else {
            Log.i(XiaopengBLEConnectionConnectTAG, "not support car key")
            return false
        }
    }

}

