7	
8	import Foundation
9	import Combine
10	
11	let XiaopengBLEConnectionConnectTAG = "[BLE连接]"
12	
13	extension XiaopengBLEConnection {
14	    func addConnMonitor() {
15	        // 监听蓝牙准许连接状态
16	        bleSwitcheCheck.$isNeedsConnect
17	            .receive(on: DispatchQueue.main)
18	            .sink {[weak self] state in
19	                self?.handleConnectionSwitch(needsConnect: state)
20	            }.store(in: &cancellables)
21	        
22	        $connectState
23	            .dropFirst()
24	            .receive(on: DispatchQueue.main)
25	            .sink {[weak self] state in
26	                self?.handleConnectStateChanged(state: state)
27	            }.store(in: &cancellables)
28	        
29	        iBeaconManager.$iBeaconState
30	            .filter({ state in
31	                state == .enter || state == .leave
32	            })
33	            .receive(on: DispatchQueue.main)
34	            .sink {[weak self] state in
35	                ApplicationState.startBackgroundTaskIfNeeded()
36	                self?.resetRetryCountAndReconnect()
37	                self?.detectIsNearCar(beaconState: state)
38	            }.store(in: &cancellables)
39	        
40	        BleCentral.shared.start().didDisconnectPeripheral
41	            .receive(on: DispatchQueue.main)
42	            .sink { [weak self] peripheral, error in
43	                self?.trackingConnect(error: error)
44	            }
45	            .store(in: &cancellables)
46	    }
47	    
48	    func setupReconnectTimer(bleHandler: BLEHandler) {
49	        self.reconnectCount = 0;
50	        self.reconnectCancellable = Timer.publish(every: bleHandler.getReconnectInterval(), on: .main, in: .common)
51	            .autoconnect()
52	            .receive(on: DispatchQueue.main)
53	            .sink {[weak self] _ in
54	                self?.handleRetryConnect()
55	            }
56	    }
57	    
58	    func removeReconnectTimer() {
59	        self.reconnectCancellable?.cancel()
60	        self.reconnectCancellable = nil
61	    }
62	    
63	    func connectIfneed() {
64	        atomicExecuteConnectionCheck {
65	            self.performConnectIfNeeded()
66	        }
67	    }
68	    
69	    /// 外部调用接口 - 强制断开连接（不检查状态）
70	    func forceDisconnect() {
71	        Log.i(XiaopengBLEConnectionConnectTAG, "强制断开蓝牙连接")
72	        self.bleHandler?.disconnect()
73	    }
74	    
75	    /// 重置重试次数并重连
76	    func resetRetryCountAndReconnect() {
77	        self.reconnectCount = 0
78	        self.connectIfneed()
79	    }
80	    
81	    // MARK: - 连接状态统一控制入口
82	    private func atomicExecuteConnectionCheck(_ operation: @escaping () -> Void) {
83	        DispatchQueue.main.async {
84	            operation()
85	        }
86	    }
87	    
88	    /// 处理连接状态变化（由 $connectState 触发）
89	    private func handleConnectStateChanged(state: BLEConnectionState) {
90	        Log.i(XiaopengBLEConnectionConnectTAG, "连接状态变化", "state: \(state)")
91	        // 连接成功后的业务逻辑
92	        if state == .Available {
93	            self.reconnectCount = 0
94	            self.notifyCarState()
95	            self.notifyNeededData()
96	            self.trackingConnect(error: nil)
97	        } else if state == .NotConnected {
98	            if let selfKeyHandler = self.bleHandler as? BLESelfKeyHandler {
99	                self.connectIfneed()
100	            }
101	        }
102	    }
103	    
104	    /// 处理连接开关变化（由 isNeedsConnect 触发）
105	    private func handleConnectionSwitch(needsConnect: Bool) {
106	        if needsConnect {
107	            self.connectIfneed()
108	        } else {
109	            self.needDisconnect()
110	        }
111	    }
112	    
113	    /// 原子性连接操作（仅在需要时执行）
114	    private func performConnectIfNeeded() {
115	        guard bleSwitcheCheck.isNeedsConnect else {
116	            Log.i(XiaopengBLEConnectionConnectTAG, "连接检查", "不需要连接")
117	            return
118	        }
119	        
120	        guard let handler = self.bleHandler else {
121	            Log.i(XiaopengBLEConnectionConnectTAG, "连接检查", "handler 为 nil")
122	            return
123	        }
124	        
125	        let connectState = self.connectState
126	        // 如果状态不一致，先同步状态
127	        if connectState != handler.state {
128	            DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) {
129	                if connectState == handler.state {
130	                    self.connectIfneed()
131	                }
132	            }
133	            Log.i(XiaopengBLEConnectionConnectTAG, "❌ 状态不一致！connectState 应为 \(handler.state)，正在同步...")
134	            return
135	        }
136	        
137	        guard connectState == .NotConnected else {
138	            Log.i(XiaopengBLEConnectionConnectTAG, "连接检查", "当前状态不是未连接: \(connectState)，无需发起连接")
139	            return
140	        }
141	        
142	        Log.i(XiaopengBLEConnectionConnectTAG, "✅ 蓝牙需要连接，发起连接")
143	        handler.connect()
144	    }
145	    
146	    
147	    private func handleRetryConnect() {
148	        guard BleCentral.shared.bleState == .poweredOn else {
149	            return
150	        }
151	        
152	        guard let handler = self.bleHandler else {
153	            return
154	        }
155	        
156	        let connectState = self.connectState
157	        // 如果状态不一致，先同步状态
158	        if connectState != handler.state {
159	            DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) {
160	                if connectState == handler.state {
161	                    self.connectIfneed()
162	                }
163	            }
164	            Log.i(XiaopengBLEConnectionConnectTAG, "❌ 状态不一致！connectState 应为 \(handler.state)，正在同步...")
165	            return
166	        }
167	        
168	        guard connectState != .Available else {
169	            return
170	        }
171	        
172	        if self.reconnectCount <= handler.getReconnectCount() {
173	            // 检查是否处于连接中（peripheral 为 nil 时视为未连接，会继续后续重连流程）
174	            if let selfKeyHandler = handler as? BLESelfKeyHandler {
175	                if selfKeyHandler.device.peripheral?.state == .connected {
176	                    Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙连接检查", "处于连接中, 不断开")
177	                    return
178	                }
179	                if connectState == .NotConnected {
180	                    Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙连接检查", "检查到蓝牙未连接，检测是否需要连接")
181	                    self.connectIfneed()
182	                    return
183	                }
184	                guard self.checkDisconnectIfNeed() else {
185	                    return
186	                }
187	                self.reconnectCount += 1
188	                if self.reconnectCount >= 5 && self.tboxRunException {
189	                    NotificationCenter.default.post(name: VehicleNotification.rescueKeyConnectFailedMoreTimeNotification,
190	                                                    object: nil,
191	                                                    userInfo: nil)
192	                    return
193	                }
194	                Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙重连", "断开重连：\(self.reconnectCount)")
195	                self.bleSwitcheCheck.disconnect(waitTime: 0.2)
196	            } else {
197	                self.reconnectCount += 1
198	                if connectState == .NotConnected {
199	                    Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙连接检查", "检查到蓝牙未连接，检测是否需要连接")
200	                    self.connectIfneed()
201	                    return
202	                }
203	            }
204	        }
205	    }
206	    
207	    func needDisconnect() {
208	        atomicExecuteConnectionCheck {
209	            if !self.bleSwitcheCheck.isNeedsConnect && self.connectState != .NotConnected {
210	                Log.i(XiaopengBLEConnectionConnectTAG, "断开蓝牙连接")
211	                self.bleHandler?.disconnect()
212	            }
213	        }
214	    }
215	    
216	    
217	    private func checkDisconnectIfNeed() -> Bool {
218	        // 间距大于8s app 休眠被唤醒 该次 不断开。
219	        let currentTime = Date().timeIntervalSince1970
220	        if currentTime - bleDisconnectInterval < 8 {
221	            bleDisconnectInterval = currentTime
222	            return true
223	        }
224	        bleDisconnectInterval = currentTime
225	        
226	        // 补充逻辑，提供 2s 的检测 否则断开
227	        DispatchQueue.main.asyncAfter(deadline: .now() + 2) { [weak self] in
228	            guard let self else { return }
229	            // 如果已经连接成功，不执行延迟断开
230	            guard self.connectState != .Available else {
231	                Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙连接检查", "已连接成功, 不执行延迟断开")
232	                return
233	            }
234	            guard let handler = self.bleHandler else {
235	                return
236	            }
237	
238	            if let selfKeyHandler = handler as? BLESelfKeyHandler {
239	                // peripheral 为 nil 时视为未连接，会继续执行断开重连
240	                if selfKeyHandler.device.peripheral?.state == .connected {
241	                    Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙连接检查", "处于连接中, 不断开")
242	                    return
243	                }
244	            }
245	
246	            self.reconnectCount += 1
247	            Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙重连", "断开重连：\(self.reconnectCount)")
248	            self.bleHandler?.disconnect()
249	        }
250	        
251	        return false
252	    }
253	    
254	    private func notifyCarState() {
255	        guard self.connectState == .Available else {
256	            return
257	        }
258	        guard let builder = bleSendDataBuilder as? BleSendDataBuilderV3 else { return }
259	        builder.buildNotifyCarStateData(cmd: [BleQueryCarStateCommand.common.rawValue, BleQueryCarStateCommand.charge.rawValue, BleQueryCarStateCommand.parking.rawValue])
260	            .flatMap({[weak self] data in
261	                guard let self else {
262	                    return Fail<AnyObject?, VehicleError>(error: VehicleError(code: .EnvironmentError, desc: "未知错误", channel: .BLE)).eraseToAnyPublisher()
263	                }
264	                return self.sendBleData(data)
265	            })
266	            .sink(
267	                receiveCompletion: { complete in
268	                    switch complete {
269	                    case .failure(let error):
270	                        Log.e("send notifyCarState 失败")
271	                    case .finished: break
272	                    }
273	                },
274	                receiveValue: { data in
275	                    Log.i("send notifyCarState 成功")
276	                }
277	            ).store(in: &cancellables)
278	    }
279	    
280	    private func sendUserInfo() {
281	        
282	        guard self.connectState == .Available else {
283	            return
284	        }
285	        
286	        guard let builder = bleSendDataBuilder as? BleSendDataBuilder else { return }
287	        let userInfo: [String : Any] = ["u": presenter?.uid ?? 0,
288	                                        "n": UserInfo.shared.nickname ?? "",
289	                                        "m": Http.deviceModelName()]
290	        
291	        let jsonData = try? JSONSerialization.data(withJSONObject: userInfo, options: [])
292	        guard let userInfoStr = String(data: jsonData!, encoding: .utf8) else {
293	            return
294	        }
295	        Log.i("蓝牙连接后发送用户信息", userInfoStr)
296	        
297	        builder.buildUserInfoData(userInfoString: userInfoStr)
298	            .flatMap({[weak self] data in
299	                guard let self else {
300	                    return Fail<AnyObject?, VehicleError>(error: VehicleError(code: .EnvironmentError, desc: "未知错误", channel: .BLE)).eraseToAnyPublisher()
301	                }
