355	    private func notifyNeededData() {
356	        self.keySettingData = self.getVaildKeySettingData()
357	        guard let presenter = self.presenter else {
358	            return
359	        }
360	        guard self.connectState == .Available else {
361	            return
362	        }
363	        guard let builder = bleSendDataBuilder as? BleSendDataBuilderV3 else { return }
364	        
365	        // 构建所有需要发送的数据
366	        let customeData = builder.pollingCustomeDataV2(
367	            isWelcome: self.keySettingData.unlockIsWelcome,
368	            pollingSwitch: self.keySettingData.pollingMode.rawValue,
369	            unlockDistance: self.keySettingData.unlockDistance,
370	            lockDistance: self.keySettingData.lockDistance,
371	            isUseSelfCalibration: self.keySettingData.isUseSelfCalibration(),
372	            selfClibrationData: self.keySettingData.fetchSelfCalibrationDataKey()
373	        )
374	        
375	        let enableData = builder.pollingEnableConfigDataV2(
376	            pollingEnableSwitch: self.keySettingData.pollingEnableSwitch
377	        )
378	        
379	        let parkingLimitData = builder.parkingLimitDistanceDataV2(
380	            isLimit: UInt8(presenter.vehiclePreference.parkLimitSixMeter ? 1 : 0)
381	        )
382	        
383	        let deviceModelData = builder.deviceModelDataV2(deviceModel: BleAuthData.getDeviceModel())
384	        
385	        // 收集所有非空数据
386	        let allData: [Data?] = [
387	            customeData,
388	            enableData,
389	            parkingLimitData,
390	            deviceModelData
391	        ]
392	        
393	        Log.i(XiaopengBLEConnectionConnectTAG, "准备发送组合数据", """
394	            customeData: \(customeData?.count ?? 0) bytes
395	            enableData: \(enableData?.count ?? 0) bytes
396	            parkingLimitData: \(parkingLimitData?.count ?? 0) bytes
397	            deviceModelData: \(deviceModelData?.count ?? 0) bytes
398	            """)
399	        
400	        let combinedDataArray = self.optimizeCombination(allData, maxBytes: 196)
401	        
402	        // 如果组合后的数组为空，直接返回
403	        guard !combinedDataArray.isEmpty else {
404	            Log.w(XiaopengBLEConnectionConnectTAG, "no vaild data to notify")
405	            return
406	        }
407	        
408	        guard let handleDataArray = builder.combinedNotityData(combinedData: combinedDataArray) else { return }
409	        
410	        // 发送组合后的数据
411	        builder.buildNotifyCombinedData(combinedData: handleDataArray)
412	            .flatMap({[weak self] data in
413	                guard let self else {
414	                    return Fail<AnyObject?, VehicleError>(error: VehicleError(code: .EnvironmentError, desc: "未知错误", channel: .BLE)).eraseToAnyPublisher()
415	                }
416	                return self.sendBleData(data)
417	            })
418	            .sink(
419	                receiveCompletion: { complete in
420	                    switch complete {
421	                    case .failure(let error):
422	                        Log.e("buildNotifyCombinedData 失败")
423	                    case .finished: break
424	                    }
425	                },
426	                receiveValue: { data in
427	                    Log.i("buildNotifyCombinedData 成功")
428	                }
429	            ).store(in: &cancellables)
430	    }
431	    
432	    private func optimizeCombination(_ dataArray: [Data?], maxBytes: Int = 200) -> [Data] {
433	        let validDataArray = dataArray.compactMap { $0 }
434	        
435	        guard !validDataArray.isEmpty else {
436	            return []
437	        }
438	        
439	        var result: [Data] = []
440	        var currentGroup = Data()
441	        
442	        // 按数据大小排序（降序），优先放大的数据
443	        let sortedData = validDataArray.sorted { $0.count > $1.count }
444	        
445	        Log.i(XiaopengBLEConnectionConnectTAG, "[数据组合] 原始数据数量: \(validDataArray.count)")
446	        
447	        for data in sortedData {
448	            // 如果单个数据就超过限制，单独发送
449	            if data.count > maxBytes {
450	                Log.w(XiaopengBLEConnectionConnectTAG, "[数据组合] 单个数据大小 \(data.count) bytes 超过限制 \(maxBytes) bytes，将单独发送")
451	                result.append(data)
452	                continue
453	            }
454	            
455	            // 尝试添加到当前组
456	            if currentGroup.count + data.count <= maxBytes {
457	                currentGroup.append(data)
458	            } else {
459	                // 当前组已满，开启新组
460	                if !currentGroup.isEmpty {
461	                    result.append(currentGroup)
462	                }
463	                currentGroup = data
464	            }
465	        }
466	        
467	        // 添加最后一组
468	        if !currentGroup.isEmpty {
469	            result.append(currentGroup)
470	        }
471	        
472	        Log.i(XiaopengBLEConnectionConnectTAG, "[数据组合] 组合后数量: \(result.count)")
473	        
474	        return result
475	    }
476	}
