574	    private enum DetectStopReason {
575	        case timeout        // 超时
576	        case connected      // 蓝牙已连接
577	        case manual         // 手动停止
578	    }
579	    
580	    func detectIsNearCar(beaconState: IBeaconState, _ timeout: TimeInterval = 60) {
581	        if beaconState == .enter {
582	            guard let presenter = self.presenter else {
583	                Log.i(tag:"detect", "presenter is nil")
584	                return
585	            }
586	            if presenter.vehiclePreference.function.CCC_DK_THIRD == false{
587	                Log.i(tag:"detect", "presenter is nil")
588	                return
589	            }
590	            guard let macAddress = presenter.digitalKeyManager?.validBlePrivateKey()?.bleInfo?.macAddress else {
591	                Log.i(tag:"detect", "macAddress is nil")
592	                return
593	            }
594	            guard presenter.digitalKeyManager?.vaildBleKeyCategory() == .PHONE_UWB_KEY else {
595	                Log.i(tag:"detect", "current key is not uwb key")
596	                return
597	            }
598	            guard self.isDetecting == false else {
599	                Log.i(tag:"detect", "detect is working")
600	                return
601	            }
602	            if self.connectState == .Available {
603	                Log.i(tag:"detect", "car key is connected, no need to detect")
604	                return
605	            }
606	            self.isDetecting = true
607	            Log.i(tag:"detect", "begin detect, timeout: \(timeout)秒")
608	            self.detectCancellables?.removeAll()
609	            self.discoveryArray?.removeAll()
610	            self.detectCancellables = Set<AnyCancellable>()
611	            self.discoveryArray = []
612	            self.detectBeginTime = CACurrentMediaTime()
613	            let ssidPrefix = presenter.vehiclePreference.abilityConfig.bleSsidPrefix
614	            let detectDevice = BleDevice(ssidPrefix: ssidPrefix, macAddress: macAddress, useScanUUIDs: true, useRssiNotify: false)
615	            self.detectDevice = detectDevice
616	            
617	            // 超时触发器
618	            let timeoutTrigger = Timer.publish(every: timeout, on: .main, in: .common)
619	                .autoconnect()
620	                .first()
621	                .map { _ in DetectStopReason.timeout }
622	            
623	            // 连接成功触发器
624	            let connectionTrigger = self.$connectState
625	                .filter { $0 == .Available }
626	                .first()
627	                .map { _ in DetectStopReason.connected }
628	            
629	            // 合并触发器：任一触发即停止
630	            let stopTrigger = Publishers.Merge(timeoutTrigger, connectionTrigger)
631	                .first()
632	                .handleEvents(receiveOutput: { [weak self] reason in
633	                    guard let self = self else { return }
634	                    switch reason {
635	                    case .timeout:
636	                        Log.i(tag:"detect", "超时触发器触发（\(timeout)秒）")
637	                    case .connected:
638	                        Log.i(tag:"detect", "蓝牙已连接，停止扫描")
639	                    case .manual:
640	                        Log.i(tag:"detect", "手动停止扫描")
641	                    }
642	                    self.stopDetecting(reason: reason)
643	                })
644	            
645	            // 扫描流：当 stopTrigger 触发时自动停止
646	            let detectMonitor = detectDevice.startDetect()
647	                .prefix(untilOutputFrom: stopTrigger)
648	                .sink(receiveValue: { [weak self] discovery in
649	                    guard let self = self else { return }
650	                    Log.i(tag:"detect", "扫描到设备，rssi:\(discovery.rssi ?? 0)db, name:\(discovery.peripheral.name ?? "nil")")
651	                    self.discoveryArray?.append(discovery)
652	                })
653	            
654	            self.detectCancellables?.insert(detectMonitor)
655	        }
656	    }
657	    
658	    private func stopDetecting(reason: DetectStopReason) {
659	        // 停止扫描并清理资源
660	        self.detectDevice?.stopScan()
661	        self.isDetecting = false
662	        self.detectCancellables?.removeAll()
663	        self.handleSuccessDeletctFlow(reason: reason)
664	        self.detectBeginTime = 0
665	    }
666	    
667	    private func handleSuccessDeletctFlow(reason: DetectStopReason) {
668	        guard let discoveryArray = self.discoveryArray, discoveryArray.count > 0 else {
669	            Log.i(tag:"detect", "没有扫描到设备")
670	            return
671	        }
672	        var leastCount: Int = 0 // -70db
673	        var lessCount: Int = 0 //
674	        var middleCount: Int = 0
675	        var greatCount: Int = 0
676	        for discovery in discoveryArray {
677	            guard let rssi = discovery.rssi, rssi < 0 else {
678	                continue
679	            }
680	            if rssi >= -60 && rssi <= 0 {
681	                greatCount += 1
682	            } else if rssi < -60 && rssi >= -65 {
683	                middleCount += 1
684	            } else if rssi < -65 && rssi >= -70 {
685	                lessCount += 1
686	            } else {
687	                leastCount += 1
688	            }
689	        }
690	        let currentTime = CACurrentMediaTime()
691	        let duration = currentTime - (self.detectBeginTime ?? currentTime)
692	        Log.i(tag:"detect", "扫描结果 近距离数量:\(greatCount) 中距离数量:\(middleCount) 远距离数量:\(lessCount) 极远距离数量:\(leastCount) 扫描时长:\(String(format: "%.2f", duration))秒, carKey连接状态：\(self.connectState)")
693	        Statistics.trackingCarKeyExceptionScanResult(isInBackground: AppRunState.shared.isInBackground, isConnect: reason == .connected ? true : false, rssi_times_1: leastCount, rssi_times_2: greatCount, rssi_times_3: middleCount, rssi_times_4: lessCount, scan_time: Int(duration))
694	    }
695	}
