//
//  XiaopengBLEConnection+Connect.swift
//  XPVehicleSDK
//
//  Created by xp on 2024/4/26.
//

import Foundation
import Combine

let XiaopengBLEConnectionConnectTAG = "[BLE连接]"

extension XiaopengBLEConnection {
    func addConnMonitor() {
        // 监听蓝牙准许连接状态
        bleSwitcheCheck.$isNeedsConnect
            .receive(on: DispatchQueue.main)
            .sink {[weak self] state in
                self?.handleConnectionSwitch(needsConnect: state)
            }.store(in: &cancellables)

        $connectState
            .dropFirst()
            .receive(on: DispatchQueue.main)
            .sink {[weak self] state in
                self?.handleConnectStateChanged(state: state)
            }.store(in: &cancellables)

        iBeaconManager.$iBeaconState
            .filter({ state in
                state == .enter || state == .leave
            })
            .receive(on: DispatchQueue.main)
            .sink {[weak self] state in
                ApplicationState.startBackgroundTaskIfNeeded()
                self?.resetRetryCountAndReconnect()
                self?.detectIsNearCar(beaconState: state)
            }.store(in: &cancellables)

        BleCentral.shared.start().didDisconnectPeripheral
            .receive(on: DispatchQueue.main)
            .sink { [weak self] peripheral, error in
                self?.trackingConnect(error: error)
            }
            .store(in: &cancellables)
    }

    func setupReconnectTimer(bleHandler: BLEHandler) {
        self.reconnectCount = 0;
        self.reconnectCancellable = Timer.publish(every: bleHandler.getReconnectInterval(), on: .main, in: .common)
            .autoconnect()
            .receive(on: DispatchQueue.main)
            .sink {[weak self] _ in
                self?.handleRetryConnect()
            }
    }

    func removeReconnectTimer() {
        self.reconnectCancellable?.cancel()
        self.reconnectCancellable = nil
    }

    func connectIfneed() {
        atomicExecuteConnectionCheck {
            self.performConnectIfNeeded()
        }
    }

    /// 外部调用接口 - 强制断开连接（不检查状态）
    func forceDisconnect() {
        Log.i(XiaopengBLEConnectionConnectTAG, "强制断开蓝牙连接")
        self.bleHandler?.disconnect()
    }

    /// 重置重试次数并重连
    func resetRetryCountAndReconnect() {
        self.reconnectCount = 0
        self.connectIfneed()
    }

    // MARK: - 连接状态统一控制入口
    private func atomicExecuteConnectionCheck(_ operation: @escaping () -> Void) {
        DispatchQueue.main.async {
            operation()
        }
    }

    /// 处理连接状态变化（由 $connectState 触发）
    private func handleConnectStateChanged(state: BLEConnectionState) {
        Log.i(XiaopengBLEConnectionConnectTAG, "连接状态变化", "state: \(state)")
        // 连接成功后的业务逻辑
        if state == .Available {
            self.reconnectCount = 0
            self.notifyCarState()
            self.notifyNeededData()
            self.trackingConnect(error: nil)
        } else if state == .NotConnected {
            if let selfKeyHandler = self.bleHandler as? BLESelfKeyHandler {
                self.connectIfneed()
            }
        }
    }

    /// 处理连接开关变化（由 isNeedsConnect 触发）
    private func handleConnectionSwitch(needsConnect: Bool) {
        if needsConnect {
            self.connectIfneed()
        } else {
            self.needDisconnect()
        }
    }

    /// 原子性连接操作（仅在需要时执行）
    private func performConnectIfNeeded() {
        guard bleSwitcheCheck.isNeedsConnect else {
            Log.i(XiaopengBLEConnectionConnectTAG, "连接检查", "不需要连接")
            return
        }

        guard let handler = self.bleHandler else {
            Log.i(XiaopengBLEConnectionConnectTAG, "连接检查", "handler 为 nil")
            return
        }

        let connectState = self.connectState
        // 如果状态不一致，先同步状态
        if connectState != handler.state {
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) {
                if connectState == handler.state {
                    self.connectIfneed()
                }
            }
            Log.i(XiaopengBLEConnectionConnectTAG, "❌ 状态不一致！connectState 应为 \(handler.state)，正在同步...")
            return
        }

        guard connectState == .NotConnected else {
            Log.i(XiaopengBLEConnectionConnectTAG, "连接检查", "当前状态不是未连接: \(connectState)，无需发起连接")
            return
        }

        Log.i(XiaopengBLEConnectionConnectTAG, "✅ 蓝牙需要连接，发起连接")
        handler.connect()
    }


    private func handleRetryConnect() {
        guard BleCentral.shared.bleState == .poweredOn else {
            return
        }

        guard let handler = self.bleHandler else {
            return
        }

        let connectState = self.connectState
        // 如果状态不一致，先同步状态
        if connectState != handler.state {
            DispatchQueue.main.asyncAfter(deadline: .now() + 0.5) {
                if connectState == handler.state {
                    self.connectIfneed()
                }
            }
            Log.i(XiaopengBLEConnectionConnectTAG, "❌ 状态不一致！connectState 应为 \(handler.state)，正在同步...")
            return
        }

        guard connectState != .Available else {
            return
        }

        if self.reconnectCount <= handler.getReconnectCount() {
            // 检查是否处于连接中（peripheral 为 nil 时视为未连接，会继续后续重连流程）
            if let selfKeyHandler = handler as? BLESelfKeyHandler {
                if selfKeyHandler.device.peripheral?.state == .connected {
                    Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙连接检查", "处于连接中, 不断开")
                    return
                }
                if connectState == .NotConnected {
                    Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙连接检查", "检查到蓝牙未连接，检测是否需要连接")
                    self.connectIfneed()
                    return
                }
                guard self.checkDisconnectIfNeed() else {
                    return
                }
                self.reconnectCount += 1
                if self.reconnectCount >= 5 && self.tboxRunException {
                    NotificationCenter.default.post(name: VehicleNotification.rescueKeyConnectFailedMoreTimeNotification,
                                                    object: nil,
                                                    userInfo: nil)
                    return
                }
                Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙重连", "断开重连：\(self.reconnectCount)")
                self.bleSwitcheCheck.disconnect(waitTime: 0.2)
            } else {
                self.reconnectCount += 1
                if connectState == .NotConnected {
                    Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙连接检查", "检查到蓝牙未连接，检测是否需要连接")
                    self.connectIfneed()
                    return
                }
            }
        }
    }

    func needDisconnect() {
        atomicExecuteConnectionCheck {
            if !self.bleSwitcheCheck.isNeedsConnect && self.connectState != .NotConnected {
                Log.i(XiaopengBLEConnectionConnectTAG, "断开蓝牙连接")
                self.bleHandler?.disconnect()
            }
        }
    }


    private func checkDisconnectIfNeed() -> Bool {
        // 间距大于8s app 休眠被唤醒 该次 不断开。
        let currentTime = Date().timeIntervalSince1970
        if currentTime - bleDisconnectInterval < 8 {
            bleDisconnectInterval = currentTime
            return true
        }
        bleDisconnectInterval = currentTime

        // 补充逻辑，提供 2s 的检测 否则断开
        DispatchQueue.main.asyncAfter(deadline: .now() + 2) { [weak self] in
            guard let self else { return }
            // 如果已经连接成功，不执行延迟断开
            guard self.connectState != .Available else {
                Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙连接检查", "已连接成功, 不执行延迟断开")
                return
            }
            guard let handler = self.bleHandler else {
                return
            }

            if let selfKeyHandler = handler as? BLESelfKeyHandler {
                // peripheral 为 nil 时视为未连接，会继续执行断开重连
                if selfKeyHandler.device.peripheral?.state == .connected {
                    Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙连接检查", "处于连接中, 不断开")
                    return
                }
            }

            self.reconnectCount += 1
            Log.i(XiaopengBLEConnectionConnectTAG, "蓝牙重连", "断开重连：\(self.reconnectCount)")
            self.bleHandler?.disconnect()
        }

        return false
    }

    private func notifyCarState() {
        guard self.connectState == .Available else {
            return
        }
        guard let builder = bleSendDataBuilder as? BleSendDataBuilderV3 else { return }
        builder.buildNotifyCarStateData(cmd: [BleQueryCarStateCommand.common.rawValue, BleQueryCarStateCommand.charge.rawValue, BleQueryCarStateCommand.parking.rawValue])
            .flatMap({[weak self] data in
                guard let self else {
                    return Fail<AnyObject?, VehicleError>(error: VehicleError(code: .EnvironmentError, desc: "未知错误", channel: .BLE)).eraseToAnyPublisher()
                }
                return self.sendBleData(data)
            })
            .sink(
                receiveCompletion: { complete in
                    switch complete {
                    case .failure(let error):
                        Log.e("send notifyCarState 失败")
                    case .finished: break
                    }
                },
                receiveValue: { data in
                    Log.i("send notifyCarState 成功")
                }
            ).store(in: &cancellables)
    }

    private func sendUserInfo() {

        guard self.connectState == .Available else {
