        guard let builder = bleSendDataBuilder as? BleSendDataBuilder else { return }
        let userInfo: [String : Any] = ["u": presenter?.uid ?? 0,
                                        "n": UserInfo.shared.nickname ?? "",
                                        "m": Http.deviceModelName()]

        let jsonData = try? JSONSerialization.data(withJSONObject: userInfo, options: [])
        guard let userInfoStr = String(data: jsonData!, encoding: .utf8) else {
