    private func syncCarKeySessionKeySettingData() {
        if self.bleCategory != .PHONE_UWB_KEY {
            return
        }
        self.updatePollingConfigData()
        self.updatePollingEnableConfigData()
    }

    private func notifyNeededData() {
        self.keySettingData = self.getVaildKeySettingData()
        guard let presenter = self.presenter else {
            return
        }
        guard self.connectState == .Available else {
            return
        }
        guard let builder = bleSendDataBuilder as? BleSendDataBuilderV3 else { return }

        // 构建所有需要发送的数据
        let customeData = builder.pollingCustomeDataV2(
            isWelcome: self.keySettingData.unlockIsWelcome,
            pollingSwitch: self.keySettingData.pollingMode.rawValue,
            unlockDistance: self.keySettingData.unlockDistance,
            lockDistance: self.keySettingData.lockDistance,
            isUseSelfCalibration: self.keySettingData.isUseSelfCalibration(),
            selfClibrationData: self.keySettingData.fetchSelfCalibrationDataKey()
        )

        let enableData = builder.pollingEnableConfigDataV2(
            pollingEnableSwitch: self.keySettingData.pollingEnableSwitch
        )

        let parkingLimitData = builder.parkingLimitDistanceDataV2(
            isLimit: UInt8(presenter.vehiclePreference.parkLimitSixMeter ? 1 : 0)
        )

        let deviceModelData = builder.deviceModelDataV2(deviceModel: BleAuthData.getDeviceModel())

        // 收集所有非空数据
        let allData: [Data?] = [
            customeData,
            enableData,
            parkingLimitData,
            deviceModelData
        ]

        Log.i(XiaopengBLEConnectionConnectTAG, "准备发送组合数据", """
            customeData: \(customeData?.count ?? 0) bytes
            enableData: \(enableData?.count ?? 0) bytes
            parkingLimitData: \(parkingLimitData?.count ?? 0) bytes
            deviceModelData: \(deviceModelData?.count ?? 0) bytes
            """)

        let combinedDataArray = self.optimizeCombination(allData, maxBytes: 196)

        // 如果组合后的数组为空，直接返回
        guard !combinedDataArray.isEmpty else {
            Log.w(XiaopengBLEConnectionConnectTAG, "no vaild data to notify")
            return
        }

        guard let handleDataArray = builder.combinedNotityData(combinedData: combinedDataArray) else { return }

        // 发送组合后的数据
        builder.buildNotifyCombinedData(combinedData: handleDataArray)
            .flatMap({[weak self] data in
                guard let self else {
                    return Fail<AnyObject?, VehicleError>(error: VehicleError(code: .EnvironmentError, desc: "未知错误", channel: .BLE)).eraseToAnyPublisher()
                }
                return self.sendBleData(data)
            })
            .sink(
                receiveCompletion: { complete in
                    switch complete {
                    case .failure(let error):
                        Log.e("buildNotifyCombinedData 失败")
                    case .finished: break
                    }
                },
                receiveValue: { data in
                    Log.i("buildNotifyCombinedData 成功")
                }
            ).store(in: &cancellables)
    }

    private func optimizeCombination(_ dataArray: [Data?], maxBytes: Int = 200) -> [Data] {
        let validDataArray = dataArray.compactMap { $0 }

        guard !validDataArray.isEmpty else {
            return []
        }

        var result: [Data] = []
        var currentGroup = Data()

        // 按数据大小排序（降序），优先放大的数据
        let sortedData = validDataArray.sorted { $0.count > $1.count }

        Log.i(XiaopengBLEConnectionConnectTAG, "[数据组合] 原始数据数量: \(validDataArray.count)")

        for data in sortedData {
            // 如果单个数据就超过限制，单独发送
            if data.count > maxBytes {
                Log.w(XiaopengBLEConnectionConnectTAG, "[数据组合] 单个数据大小 \(data.count) bytes 超过限制 \(maxBytes) bytes，将单独发送")
                result.append(data)
                continue
            }

            // 尝试添加到当前组
            if currentGroup.count + data.count <= maxBytes {
                currentGroup.append(data)
            } else {
                // 当前组已满，开启新组
                if !currentGroup.isEmpty {
                    result.append(currentGroup)
                }
                currentGroup = data
            }
        }

        // 添加最后一组
        if !currentGroup.isEmpty {
            result.append(currentGroup)
        }

        Log.i(XiaopengBLEConnectionConnectTAG, "[数据组合] 组合后数量: \(result.count)")

        return result
    }
}

extension XiaopengBLEConnection: BleKeyV3AuthFactorDelegate {

    func getVaildKeyCertMessage(complete: ((String?) -> Void)?) {
        if let keyManage = self.presenter?.digitalKeyManager?.validBlePrivateKey() {
            keyManage.getOneKeyMessage(skipBioAuth: true) { keyMessage in
                if let ifaa = keyMessage {
                    complete?(ifaa)
                } else {
                    complete?(nil)
                }
            } fail: { error in
                complete?(nil)
            }

        } else {
            complete?(nil)
        }
    }

    func getKeySettingData() -> XiaopengKeyDataSetting {
        return self.keySettingData
    }

    func getVaildKeySettingData() -> XiaopengKeyDataSetting {
        guard let keySettingData = ProxyManger.shared.keySettingProxy?.getKeySettingData?(vin: self.presenter?.vin ?? "") else {
            return XiaopengKeyDataSetting()
        }
        Log.i("XiaopengBLEConnection", "keySettingData: \(keySettingData)")
        let pollingWelcome: Bool = keySettingData[DatabaseConstants.kWelcomeModeKey as String] as? Bool ?? true
        var runMode: VehiclePollingMode = .BOTH
        if let rawValue = keySettingData[DatabaseConstants.kPollingRunModeKey as String] as? UInt8,
           let pollingRunMode = VehiclePollingMode(rawValue: rawValue) {
            runMode = pollingRunMode
        }
        let unlockDistance: Float = keySettingData[DatabaseConstants.kUnlockDistanceKey as String] as? Float ?? 4
        let lockDistance: Float = keySettingData[DatabaseConstants.kLockDistanceKey as String] as? Float ?? 7
        var txPower:[String]? = nil
        if let txPowerArray = keySettingData[DatabaseConstants.kSelfCalibrationTxPowerV3Key as String] as? [String] {
            txPower = txPowerArray
        }
        let pollingEnableSwitch: Bool = keySettingData[DatabaseConstants.kPollingEnableSwitchKey as String] as? Bool ?? true
        bleSwitcheCheck.setPollingActive(runMode != .NONE)
        let isDriverMode = (keySettingData[DatabaseConstants.kIsDriverMode as String] as? Bool) ?? true
        bleSwitcheCheck.needDisconnectInBackground = !isDriverMode // 乘客模式需要在后台断开连接，主驾模式不需要
        return XiaopengKeyDataSetting(pollingMode: runMode, unlockDistance: unlockDistance, lockDistance: lockDistance, unlockIsWelcome: pollingWelcome, txPowerArray: txPower, pollingEnableSwitch: pollingEnableSwitch, isDriverMode: isDriverMode)
    }

    private func trackingConnect(error: Error?) {
        if connectState == .Available {
            connectedTime = Date().timeIntervalSince1970
        }

        guard connectState == .NotConnected else {
            return
        }

        guard let connectedTime else {
            return
        }

        var code = 0
        let _error = error as? NSError

        if _error?.code == 6 {
            code = 6
        }

        if BleCentral.shared.bleState != .poweredOn {
            code = 1
        }

        let duration = Int64((Date().timeIntervalSince1970 - connectedTime) * 1000)
        self.connectedTime = nil

        Statistics.trackingBleDisconnect(car_type: presenter?.vehiclePreference.vehicleTypeCode ?? "", duration: duration, code: code, ble_position: 1)
    }

}

extension XiaopengBLEConnection: BleKeyV3RescueAuthFactorDelegate {

