extension XiaopengBLEConnection {
    private enum DetectStopReason {
        case timeout        // 超时
        case connected      // 蓝牙已连接
        case manual         // 手动停止
    }

    func detectIsNearCar(beaconState: IBeaconState, _ timeout: TimeInterval = 60) {
        if beaconState == .enter {
            guard let presenter = self.presenter else {
                Log.i(tag:"detect", "presenter is nil")
                return
            }
            if presenter.vehiclePreference.function.CCC_DK_THIRD == false{
                Log.i(tag:"detect", "presenter is nil")
                return
            }
            guard let macAddress = presenter.digitalKeyManager?.validBlePrivateKey()?.bleInfo?.macAddress else {
                Log.i(tag:"detect", "macAddress is nil")
                return
            }
            guard presenter.digitalKeyManager?.vaildBleKeyCategory() == .PHONE_UWB_KEY else {
                Log.i(tag:"detect", "current key is not uwb key")
                return
            }
            guard self.isDetecting == false else {
                Log.i(tag:"detect", "detect is working")
                return
            }
            if self.connectState == .Available {
                Log.i(tag:"detect", "car key is connected, no need to detect")
                return
            }
            self.isDetecting = true
            Log.i(tag:"detect", "begin detect, timeout: \(timeout)秒")
            self.detectCancellables?.removeAll()
            self.discoveryArray?.removeAll()
            self.detectCancellables = Set<AnyCancellable>()
            self.discoveryArray = []
            self.detectBeginTime = CACurrentMediaTime()
            let ssidPrefix = presenter.vehiclePreference.abilityConfig.bleSsidPrefix
            let detectDevice = BleDevice(ssidPrefix: ssidPrefix, macAddress: macAddress, useScanUUIDs: true, useRssiNotify: false)
            self.detectDevice = detectDevice

            // 超时触发器
            let timeoutTrigger = Timer.publish(every: timeout, on: .main, in: .common)
                .autoconnect()
                .first()
                .map { _ in DetectStopReason.timeout }

            // 连接成功触发器
            let connectionTrigger = self.$connectState
                .filter { $0 == .Available }
                .first()
                .map { _ in DetectStopReason.connected }

            // 合并触发器：任一触发即停止
            let stopTrigger = Publishers.Merge(timeoutTrigger, connectionTrigger)
                .first()
                .handleEvents(receiveOutput: { [weak self] reason in
                    guard let self = self else { return }
                    switch reason {
                    case .timeout:
                        Log.i(tag:"detect", "超时触发器触发（\(timeout)秒）")
                    case .connected:
                        Log.i(tag:"detect", "蓝牙已连接，停止扫描")
                    case .manual:
                        Log.i(tag:"detect", "手动停止扫描")
                    }
                    self.stopDetecting(reason: reason)
                })

            // 扫描流：当 stopTrigger 触发时自动停止
            let detectMonitor = detectDevice.startDetect()
                .prefix(untilOutputFrom: stopTrigger)
                .sink(receiveValue: { [weak self] discovery in
                    guard let self = self else { return }
                    Log.i(tag:"detect", "扫描到设备，rssi:\(discovery.rssi ?? 0)db, name:\(discovery.peripheral.name ?? "nil")")
                    self.discoveryArray?.append(discovery)
                })

            self.detectCancellables?.insert(detectMonitor)
        }
    }

    private func stopDetecting(reason: DetectStopReason) {
        // 停止扫描并清理资源
        self.detectDevice?.stopScan()
        self.isDetecting = false
        self.detectCancellables?.removeAll()
        self.handleSuccessDeletctFlow(reason: reason)
        self.detectBeginTime = 0
    }

    private func handleSuccessDeletctFlow(reason: DetectStopReason) {
        guard let discoveryArray = self.discoveryArray, discoveryArray.count > 0 else {
            Log.i(tag:"detect", "没有扫描到设备")
            return
        }
        var leastCount: Int = 0 // -70db
        var lessCount: Int = 0 //
        var middleCount: Int = 0
        var greatCount: Int = 0
        for discovery in discoveryArray {
            guard let rssi = discovery.rssi, rssi < 0 else {
                continue
            }
            if rssi >= -60 && rssi <= 0 {
                greatCount += 1
            } else if rssi < -60 && rssi >= -65 {
                middleCount += 1
            } else if rssi < -65 && rssi >= -70 {
                lessCount += 1
            } else {
                leastCount += 1
            }
        }
        let currentTime = CACurrentMediaTime()
        let duration = currentTime - (self.detectBeginTime ?? currentTime)
        Log.i(tag:"detect", "扫描结果 近距离数量:\(greatCount) 中距离数量:\(middleCount) 远距离数量:\(lessCount) 极远距离数量:\(leastCount) 扫描时长:\(String(format: "%.2f", duration))秒, carKey连接状态：\(self.connectState)")
        Statistics.trackingCarKeyExceptionScanResult(isInBackground: AppRunState.shared.isInBackground, isConnect: reason == .connected ? true : false, rssi_times_1: leastCount, rssi_times_2: greatCount, rssi_times_3: middleCount, rssi_times_4: lessCount, scan_time: Int(duration))
    }
}

