    func createKey(keyCategory: DigitalKeyCategory, success: @escaping VehicleDigitalKeySuccessResponseCallback<DigitalKey>, failed: @escaping VehicleFailedCallback<VehicleError>) {
        if (keyCategory != DigitalKeyCategory.PHONE_BLE_KEY) {
            Log.e(tag:"digitalKey", "创建数字钥匙：失败 ", "不支持的类型:", keyCategory)
            failed(VehicleError(code: VehicleErrorCode.NotSupported, desc: "尚未支持，操作失败"))
          return;
        }

        if (self.vehiclePreference.abilityConfig.isSupportBleKey != true) {
            Log.e(tag:"digitalKey", "创建数字钥匙：失败 ", "isSupportBleKey != true")
