    public func removeNfcKey(success: @escaping VehicleSuccessCallback, failed: @escaping VehicleFailedCallback<VehicleError>) {
        if let plugin = self.createPlugin(keyCardType: KeyCardType.NFC_WATCH) {
            if let digitalKey = self.digitalKey(keyCardType: KeyCardType.NFC_WATCH) {
