//
//  BLESwitchCheck.swift
//  XPVehicleSDK
//
//  BLE心跳开关控制器（根据App运行状态来计算BLE心跳开关）
//   BLE心跳是默认不需要，进后台可能需要，泊车要禁用，所以这里无法统一处理前后台逻辑，
//   需要Polling和泊车分别处理前后台逻辑
//   1. Polling 开启时进后台需要开启BLE心跳
//   2. Polling 2.0 开启时前后台都需要开启BLE心跳
//   3. Polling开启时，进入泊车，需要关闭BLE心跳
//   4. 泊车还需要通知 Polling 暂停
//
//  Created by yangcy on 2024/02/04.
//

import Foundation
import Combine

@objc(XPBLESwitchCheck)
open class BLESwitchCheck: NSObject {
    weak var presenter: VehicleCommunication?

    @Published @objc private(set) open var isNeedsHeartbeat: Bool = false // 心跳开关
    @Published @objc private(set) open var isNeedsConnect: Bool = false // 是否需要 Ble 连接
    @Published @objc private(set) public var isNeedsiBeacon: Bool = false // 是否需要 iBeacon
    @Published @objc open var isWaitingToConnect: Bool = false // 是否等待连接，用于业务主动断开蓝牙，后续不会发起蓝牙连接。直到该值重新变为 false
    @Published @objc open var isSwitchBleChannel: Bool = false //
    @Published @objc open var isSendingBLECommand = false // 是否正在发送蓝牙指令
    @Published @objc private(set) public var isPollingActive: Bool = false // Polling是否激活

    @objc open var needDisconnectInBackground: Bool = false // 进入后台是否需要断开连接，乘客模式

    private var cancellables = Set<AnyCancellable>()

    init(presenter: VehicleCommunication) {
        super.init()
        self.presenter = presenter
        Log.i(tag: "BLE心跳开关", "开关初始值 isTurnOn:", isNeedsHeartbeat)

        AppRunState.shared.$isInBackground.dropFirst().sink {[weak self] flag in
            self?.calcSwitchState()
        }.store(in: &cancellables)

        AppRunState.shared.$isInVehicleControlPage.dropFirst().sink {[weak self] flag in
            self?.calcSwitchState()
        }.store(in: &cancellables)

        AppRunState.shared.$isOnParking.dropFirst().sink {[weak self] flag in
            self?.calcSwitchState()
        }.store(in: &cancellables)

        AppRunState.shared.$isDigitalKeyDeleting.dropFirst().sink {[weak self] flag in
            self?.calcSwitchState()
        }.store(in: &cancellables)

        AppRunState.shared.$isWatchReachable.dropFirst().sink {[weak self] flag in
            self?.calcSwitchState()
        }.store(in: &cancellables)

        AppRunState.shared.$isShakeActive.dropFirst().sink {[weak self] flag in
            self?.calcSwitchState()
        }.store(in: &cancellables)

        self.$isPollingActive.dropFirst().sink {[weak self] flag in
            self?.calcSwitchState()
        }.store(in: &cancellables)

        // 监听蓝牙开关状态
        BleCentral.shared.$bleState
            .receive(on: DispatchQueue.main)
            .sink {[weak self] state in
                self?.calcSwitchState()
            }.store(in: &cancellables)

        $isWaitingToConnect.dropFirst().sink {[weak self] flag in
            self?.calcSwitchState()
        }.store(in: &cancellables)

        $isSwitchBleChannel.dropFirst().sink {[weak self] flag in
            self?.calcSwitchState()
        }.store(in: &cancellables)


        $isSendingBLECommand.dropFirst().sink {[weak self] flag in
            self?.calcSwitchState()
        }.store(in: &cancellables)

        calcSwitchState()
    }

    deinit {
    }

    // 断开 多久后重连
    func disconnect(waitTime: TimeInterval) {
        self.isWaitingToConnect = true
        DispatchQueue.main.asyncAfter(deadline: .now() + waitTime) {
            self.isWaitingToConnect = false
        }
    }

    func calcSwitchState() {
        // 因为 @Published 的监听是在Value修改之前通知的，所以这里必须延后计算
        DispatchQueue.main.async() {
            var isNeedsConnect = true

            if self.isWaitingToConnect {
                isNeedsConnect = false
                Log.i(tag: "BLE连接开关", "等待连接中，不需要连接")
            }

            if self.isSwitchBleChannel {
                isNeedsConnect = false
                Log.i(tag: "BLE连接开关", "切换通道中，不需要连接")
            }

            if BleCentral.shared.start().state != .poweredOn {
                isNeedsConnect = false
                Log.i(tag: "BLE连接开关", "蓝牙未开启，不需要连接")
            }

            if (AppRunState.shared.isInBackground && !self.connectIfneedInBg && !self.isSendingBLECommand) {
                isNeedsConnect = false
                Log.i(tag: "BLE连接开关", "进入后台不需要连接")
            }

            if (self.isNeedsConnect != isNeedsConnect) {
                self.isNeedsConnect = isNeedsConnect
                Log.i(tag: "BLE连接开关", "开关值变化 isNeedsConnect:", self.isNeedsConnect, "isWaitingToConnect:", self.isWaitingToConnect, "isSwitchBleChannel:", self.isSwitchBleChannel, "isSendingBLECommand:", self.isSendingBLECommand, "isInBackground:", AppRunState.shared.isInBackground, "connectIfneedInBg:", self.connectIfneedInBg, "bleState:", BleCentral.shared.start().state.rawValue)
            }

            var turnOnCalc = false
            if (!AppRunState.shared.isOnParking) {
                if ((AppRunState.shared.isInBackground && self.isPollingActive)
                    || self.isPollingSecond) {
                    turnOnCalc = true
                }
            }

            if (self.isNeedsHeartbeat != turnOnCalc) {
                self.isNeedsHeartbeat = turnOnCalc
                Log.i(tag: "BLE心跳开关", "开关值变化 isTurnOn:", self.isNeedsHeartbeat)
            }

            var isNeedsiBeacon = false
            if (self.presenter?.vehiclePreference.function.BLE_KEY ?? false) && self.isPollingActive {
                isNeedsiBeacon = true
            }

            if (self.isNeedsiBeacon != isNeedsiBeacon) {
                self.isNeedsiBeacon = isNeedsiBeacon
                Log.i(tag: "BLE iBeacon 开关", "iBeacon 开关值变化 isTurnOn:", self.isNeedsiBeacon)
            }
        }
    }

    @objc public func setPollingActive(_ flag: Bool) {
        Log.i(tag: "BLE polling开关", "setPollingActive:", isPollingActive)
        if (self.isPollingActive != flag) {
            self.isPollingActive = flag
        }
    }

}

extension BLESwitchCheck {

    var isE28: Bool {
        presenter?.vehiclePreference.vehicleType == .E28
    }

    var connectIfneedInBg: Bool {
        if AppRunState.shared.isInBackground {
            if needDisconnectInBackground {
                return false
            }
            if isE28 {
                return false
            } else {
               return true
            }
        } else {
            return true
        }
    }

    var isPollingSecond: Bool {
        presenter?.vehiclePreference.function.IS_POLLINGSECOND ?? false
    }

    var isPollingFirst: Bool {
        presenter?.vehiclePreference.function.IS_POLLINGFIRST ?? false
    }

}

