283	            return
284	        }
285	        guard let digitalKeyManager = presenter?.digitalKeyManager as? DigitalKeyManager else {
286	            return
287	        }
288	        let pollingFirst = presenter?.vehiclePreference.function.IS_POLLINGFIRST == true
