296	    public override func send(data: Any!, success: @escaping VehicleSuccessResponseCallback, failed: @escaping VehicleFailedCallback<VehicleError>) {
297	        
298	        guard let data = data as? BleSendData else {
299	            failed(VehicleError(code: .ParamError, desc: "参数错误", channel: .BLE))
300	            return
301	        }
302	        
303	        guard connectState == .Available else {
304	            failed(VehicleError(code: .BLENotConnected, desc: "蓝牙未连接", channel: .BLE))
305	            return
306	        }
307	        
308	        DispatchQueue.main.async {
309	            self.bleSwitcheCheck.isSendingBLECommand = true
310	            self.sendBleData(data)
311	                .sink {[weak self] complete in
312	                    self?.bleSwitcheCheck.isSendingBLECommand = false
313	                    switch complete {
314	                    case .failure(let error):
315	                        failed(error)
316	                    case .finished: break
317	                    }
318	                } receiveValue: { data in
319	                    success(nil)
320	                }
321	                .store(in: &self.cancellables)
322	        }
323	        
324	    }
325	    
326	    override func cleanBleInfoCache() {
327	        bleHandler?.cleanBleInfoCache()
328	    }
329	    
330	    override func exitBleRetrieveCache() -> Bool {
331	        bleHandler?.exitBleRetrieveCache() ?? false
332	    }
333	    
334	    override func readRssi() {
335	        bleHandler?.readRssi()
336	    }
337	    
338	    func bleErrorToVehicleError(error: BleDeviceError) -> VehicleError {
339	        switch error {
340	        case .unconnectable:
341	            return VehicleError(code: .UnknownError, desc: error.description, channel: .BLE)
342	        case .writeTimeOut:
343	            return VehicleError(code: .Timeout, desc: error.description, channel: .BLE)
344	        case .writeError:
345	            return VehicleError(code: .BLEWriteError, desc:  error.description, channel: .BLE)
346	        case .bleNotConnect:
347	            return VehicleError(code: .BLENotConnected, desc: error.description, channel: .BLE)
348	        case .deviceDealloc:
349	            return VehicleError(code: .UnknownError, desc: error.description, channel: .BLE)
350	        case .characteristicNotFound:
351	            return VehicleError(code: .EnvironmentError, desc:error.description, channel: .BLE)
352	        case .unowned:
353	            return VehicleError(code: .UnknownError, desc: error.description, channel: .BLE)
354	            
355	        default:
356	            return VehicleError(code: .UnknownError, desc: error.description ?? "未知错误", channel: .BLE)
357	        }
358	    }
359	    
360	}
