//
//  BLEHandlerFactory.swift
//  XPVehicleSDK
//
//  Created by huzy2 on 2024/11/27.
//

import Foundation

struct BLEHandlerFactory {
    static func bleCreateCategory(presenter: VehicleCommunication) -> DigitalKeyCategory {
        return presenter.digitalKeyManager?.vaildBleKeyCategory() ?? .PHONE_BLE_KEY
    }

    static func createBleKeyHandler(macAddress: String?, cccVid: String?, bleCategory: DigitalKeyCategory, delegate: BLEDataParserResultDelegate, presenter: VehicleCommunication, isResuce: Bool = false) -> BLEHandler? {
        if bleCategory == .PHONE_UWB_KEY {
            guard let cccVid = cccVid else {
                Log.i(tag: "bleLife", "cccVid is nil")
                return nil
            }
            if #available(iOS 18.0, *) {
                return createCarKeyKeyBleHandler(macAddress: macAddress, cccVid: cccVid, delegate: delegate, presenter: presenter)
            } else {
                Log.i(tag: "bleLife", "system version is below iOS18.0")
                return nil
            }
        } else {
            guard let macAddress = macAddress else {
                Log.i(tag: "bleLife", "macAddress is nil")
                return nil
            }
            return createSelfKeyBleHandler(macAddress: macAddress, delegate: delegate, presenter: presenter, isResuce: isResuce)
        }
    }

    static func carKeyCCCVidIsChanged(bleHandler: BLEHandler, cccVid: String?) -> Bool {
        if #available(iOS 18.0, *) {
            if (bleHandler as? BLEKeyCarKeySessionHandler)?.cccVid == cccVid {
                return false
            } else {
                return true
            }
        } else {
            return true
        }
    }

    static private func createBleKeyV3Handler(name: String, macAddress: String, delegate: BLEDataParserResultDelegate, presenter: VehicleCommunication) -> BLEKeyV3Handler {
        let dataParser = BLEKeyV3Parser(vehicleTypeCode: presenter.vehiclePreference.vehicleTypeCode, isEncrypt: true, delegate: delegate)
        let ssidPrefix = presenter.vehiclePreference.abilityConfig.bleSsidPrefix
        guard let authDelegate = delegate as? BleKeyV3AuthFactorDelegate else {
            Log.i(tag: "bleLife", "Delegate does not conform to BleKeyV3AuthFactorDelegate.")
            return BLEKeyV3Handler(ssidPrefix: ssidPrefix, name: name, macAddress: macAddress, dataParser: dataParser, useScanUUIDs: true, uid: presenter.uid, authDelegate: nil, useRssiNotify: presenter.vehiclePreference.abilityConfig.isSupportRssiFromCar)
        }
        return BLEKeyV3Handler(ssidPrefix: ssidPrefix, name: name, macAddress: macAddress, dataParser: dataParser, useScanUUIDs: true, uid: presenter.uid, authDelegate: authDelegate, useRssiNotify: presenter.vehiclePreference.abilityConfig.isSupportRssiFromCar)
    }

    static private func createSelfKeyBleHandler(macAddress: String, delegate: BLEDataParserResultDelegate, presenter: VehicleCommunication, isResuce: Bool = false) -> BLESelfKeyHandler? {
        let digitalKey = presenter.digitalKeyManager?.validBlePrivateKey()
        let name = digitalKey?.bleInfo?.name ?? "BLE"
        let ssidPrefix = presenter.vehiclePreference.abilityConfig.bleSsidPrefix
        let bleKeyVersion = presenter.vehiclePreference.abilityConfig.bleKeyVersion
        if bleKeyVersion == .V1 {
            let dataParser = BLEKeyV1Parser(vehicleTypeCode: presenter.vehiclePreference.vehicleTypeCode, delegate: delegate)
            return BLEKeyV1Handler(ssidPrefix: ssidPrefix, name: name, macAddress: macAddress, dataParser: dataParser, useScanUUIDs: false, useRssiNotify: presenter.vehiclePreference.abilityConfig.isSupportRssiFromCar)
        } else if bleKeyVersion == .V2 {
            var needDoubleAuth = false
            if (presenter.vehiclePreference.extInfo?.supportedCapabilities(RemoteCapabilities.BLE_SECURITY_ENHANCE) == true ||
                presenter.vehiclePreference.extInfo?.supportedCapabilities(RemoteCapabilities.BLE_MUTUAL_AUTHENTICATION_REOPEN_SOFTWARE) == true) &&
                presenter.vehiclePreference.abilityConfig.isSkipVerify == false {
                needDoubleAuth = true
            } else {
                needDoubleAuth = false
            }
            var doublesidedAuthCode: String?
            doublesidedAuthCode = presenter.digitalKeyManager?.digitalKey(keyCardType: .SELF)?.doublesidedAuthCode
            let dataParser = BLEKeyV2Parser(vehicleTypeCode: presenter.vehiclePreference.vehicleTypeCode,delegate: delegate)
            dataParser.rssi_COUNT = presenter.vehiclePreference.abilityConfig.bleCount ?? 4
            return BLEKeyV2Handler(ssidPrefix: ssidPrefix, name: name, macAddress: macAddress, dataParser: dataParser, useScanUUIDs: true,needsDoublesidedAuth: needDoubleAuth, doublesidedAuthCode: doublesidedAuthCode, useRssiNotify: presenter.vehiclePreference.abilityConfig.isSupportRssiFromCar)
        } else if bleKeyVersion == .V3 {
            if isResuce {
                let dataParser = BLEKeyV3Parser(vehicleTypeCode: presenter.vehiclePreference.vehicleTypeCode, isEncrypt: true, delegate: delegate)
                guard let authDelegate = delegate as? BleKeyV3RescueAuthFactorDelegate else {
                    print("Delegate does not conform to BleKeyV3RescueAuthFactorDelegate.")
                    return BLEKeyV3RescueHandler(ssidPrefix: ssidPrefix, name: name, macAddress: macAddress, dataParser: dataParser, useScanUUIDs: true, uid: presenter.uid, authDelegate: nil)
                }
                return BLEKeyV3RescueHandler(ssidPrefix: ssidPrefix, name: name, macAddress: macAddress, dataParser: dataParser, useScanUUIDs: true, uid: presenter.uid, authDelegate: authDelegate)
            } else {
                return createBleKeyV3Handler(name: name, macAddress: macAddress, delegate: delegate, presenter: presenter)
            }
        } else {
            Log.i(tag: "bleLife", "Unsupported BLE key version.")
            return nil
        }
    }

    @available(iOS 18.0, *)
    static private func createCarKeyKeyBleHandler(macAddress: String?, cccVid: String, delegate: BLEDataParserResultDelegate, presenter: VehicleCommunication, keySetting: XiaopengKeyDataSetting? = nil) -> BLEKeyCarKeySessionHandler {
        let digitalKey = presenter.digitalKeyManager?.validBlePrivateKey()
        let name = digitalKey?.bleInfo?.name ?? "BLE"
        let dataParser = BLEKeyV3Parser(vehicleTypeCode: presenter.vehiclePreference.vehicleTypeCode, isEncrypt: false, delegate: delegate)
        var cccKeyId = presenter.digitalKeyManager?.digitalKey(keyCardType: .CCC)?.cardNo
        return BLEKeyCarKeySessionHandler(name: name, macAddress: macAddress, cccVid: cccVid, cccKeyId: cccKeyId ?? "", dataParser: dataParser)
    }
}

