import Foundation
import MMKV

@objc(XPCarKeyExceptionType)
public enum CarKeyExceptionType: Int, Codable, CustomStringConvertible {
    case None = 0
    case Error = 1
    case Timeout = 2
    case Block = 3

    public var description: String {
        switch self {
        case .None:
            return "None"
        case .Error:
            return "Error"
        case .Timeout:
            return "Timeout"
        case .Block:
            return "Block"
        }
    }
}

class CarKeyExceptionObj: Codable {
    var sysVer: String = UIDevice.current.systemVersion
    var appVer: String = Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "Unknown"
    var isInBackground: Bool = AppRunState.shared.isInBackground
    var backgroundTime: Int = AppRunState.shared.isInBackground ? Int((CACurrentMediaTime() - AppRunState.shared.backgroundTime)/1000) : 0
    var isPullAlive: Bool = XPVehicleSDK.shared.isPullAlive
    var appSwitchCount: Int = AppRunState.shared.appSwitchCount
    var exceptionType: CarKeyExceptionType = .None
    var sessionError: CarKeySessionError = .None
    var passError: CarKeyPassEventError = .None
    var cccVid: String
    var hasPrivateKey: Bool = true

    // 自定义编码键名
    enum CodingKeys: String, CodingKey {
        case sysVer = "systemVersion"
        case appVer = "appVersion"
        case isInBackground = "is_app_backend"
        case backgroundTime = "ds"
        case isPullAlive = "fromType"
        case appSwitchCount = "times"
        case exceptionType = "errorType"
        case sessionError = "error_code"
        case passError = "error_value"
        case cccVid
        case hasPrivateKey = "key_number"
    }

    @inlinable
    init(cccVid: String, exceptionType: CarKeyExceptionType = .None, sessionError: CarKeySessionError = .None, passError: CarKeyPassEventError = .None) {
        self.cccVid = cccVid
        self.exceptionType = exceptionType
        self.sessionError = sessionError
        self.passError = passError
        self.backgroundTime = AppRunState.shared.isInBackground ? Int(CACurrentMediaTime() - AppRunState.shared.backgroundTime) : 0
    }


    func encode(to encoder: Encoder) throws {
        var container = encoder.container(keyedBy: CodingKeys.self)

        // String 类型保持不变
        try container.encode(sysVer, forKey: .sysVer)
        try container.encode(appVer, forKey: .appVer)
        try container.encode(cccVid, forKey: .cccVid)

        try container.encode(isInBackground ? "1" : "0", forKey: .isInBackground)
        try container.encode(isPullAlive ? "1" : "0", forKey: .isPullAlive)
        try container.encode(hasPrivateKey ? 1 : 0, forKey: .hasPrivateKey)

        // Int 转换为字符串
        try container.encode(backgroundTime, forKey: .backgroundTime)
        try container.encode(String(appSwitchCount), forKey: .appSwitchCount)

        // Enum 的 rawValue 转换为字符串
        try container.encode(String(exceptionType.rawValue), forKey: .exceptionType)
        try container.encode(String(sessionError.rawValue), forKey: .sessionError)
        try container.encode(String(passError.rawValue), forKey: .passError)
    }

    required init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)

        // 解码基本字符串类型
        sysVer = try container.decode(String.self, forKey: .sysVer)
        appVer = try container.decode(String.self, forKey: .appVer)
        cccVid = try container.decode(String.self, forKey: .cccVid)

        // 解码字符串形式的 Bool 值 ("1"/"0")
        let isInBackgroundString = try container.decode(String.self, forKey: .isInBackground)
        isInBackground = (isInBackgroundString == "1")

        let isPullAliveString = try container.decode(String.self, forKey: .isPullAlive)
        isPullAlive = (isPullAliveString == "1")

        let hasPrivateKeyInt = try container.decode(Int.self, forKey: .hasPrivateKey)
        hasPrivateKey = (hasPrivateKeyInt == 1)

        // 解码字符串形式的 Int 值
        backgroundTime = try container.decode(Int.self, forKey: .backgroundTime) ?? 0

        let appSwitchCountString = try container.decode(String.self, forKey: .appSwitchCount)
        appSwitchCount = Int(appSwitchCountString) ?? 0 // 提供默认值

        // 解码字符串形式的枚举 rawValue
        let exceptionTypeRawValue = try container.decode(String.self, forKey: .exceptionType)
        exceptionType = CarKeyExceptionType(rawValue: Int(exceptionTypeRawValue) ?? 0) ?? .None

        let sessionErrorRawValue = try container.decode(String.self, forKey: .sessionError)
        sessionError = CarKeySessionError(rawValue: Int(sessionErrorRawValue) ?? 0) ?? .None

        let passErrorRawValue = try container.decode(String.self, forKey: .passError)
        passError = CarKeyPassEventError(rawValue: Int(passErrorRawValue) ?? 0) ?? .None
    }

    /// 转换为JSON字符串
    /// - Returns: JSON字符串，如果转换失败返回空字符串
    func toJSONString() -> String {
        let encoder = JSONEncoder()
        encoder.outputFormatting = .prettyPrinted // 可选：格式化输出

        do {
            let jsonData = try encoder.encode(self)
            if let jsonString = String(data: jsonData, encoding: .utf8) {
                return jsonString
            }
        } catch {
            Log.e("CarKeyExceptionObj", "Failed to encode to JSON: \(error)")
        }

        return ""
    }

    /// 转换为紧凑的JSON字符串（无格式化）
    /// - Returns: 紧凑的JSON字符串，如果转换失败返回空字符串
    func toCompactJSONString() -> String {
        let encoder = JSONEncoder()

        do {
            let jsonData = try encoder.encode(self)
            if let jsonString = String(data: jsonData, encoding: .utf8) {
                return jsonString
            }
        } catch {
            Log.e("CarKeyExceptionObj", "Failed to encode to JSON: \(error)")
        }

        return ""
    }

    func saveCache(key: String) {
        if let data = try? JSONEncoder().encode(self) {
            MMKV.default()?.set(data, forKey: key)  // ✅ 使用 set 而不是 setValue
            MMKV.default()?.sync()
        }
    }

    static func loadCache(key: String) -> CarKeyExceptionObj? {
        guard let data = MMKV.default()?.data(forKey: key) else {
            return nil
        }
        do {
            let decoder = JSONDecoder()
            let obj = try decoder.decode(CarKeyExceptionObj.self, from: data)
            return obj
        } catch {
            Log.i(tag: "CarKeyExceptionObj", "decode error:", error);
            return nil
        }
    }

    static func removeCache(key: String) {
        MMKV.default()?.removeValue(forKey: key)
        MMKV.default()?.sync()
    }

}

