127	class CarKeySessionAccesser: NSObject, CarKeySessionAccesserProtocol {
128	    
129	    /// 在 detached task 中执行带超时的异步操作，结果通过 completion 回调
130	    @discardableResult
131	    static func detachedWithTimeout<R>(
132	        seconds: TimeInterval,
133	        operation: @escaping () async throws -> R,
134	        onSuccess: @escaping (R) -> Void,
135	        onTimeout: @escaping () -> Void,
136	        onError: @escaping (Error) -> Void
137	    ) -> Task<Void, Never> {
138	        Task.detached(priority: .userInitiated) {
139	            do {
140	                let result = try await withThrowingTaskGroup(of: R.self) { group in
141	                    group.addTask { try await operation() }
142	                    group.addTask {
143	                        try await Task.sleep(nanoseconds: UInt64(seconds * 1_000_000_000))
144	                        throw CarKeySessionError.TaskTimedOut
145	                    }
146	                    let result = try await group.next()!
147	                    group.cancelAll()
148	                    return result
149	                }
150	                onSuccess(result)
151	            } catch CarKeySessionError.TaskTimedOut {
152	                onTimeout()
153	            } catch {
154	                onError(error)
155	            }
156	        }
157	    }
158	    
159	    private var _carKeySession: CarKeyRemoteControlSession?
160	    var carKeySession: CarKeyRemoteControlSession? {
161	        get {
162	            lock.lock()
163	            defer { lock.unlock() }
164	            return _carKeySession
165	        }
166	        set {
167	            lock.lock()
168	            _carKeySession = newValue
169	            lock.unlock()
170	        }
171	    }
172	    private var _vehicleIdentifier: String
173	    var vehicleIdentifier: String {
174	        get {
175	            lock.lock()
176	            defer { lock.unlock() }
177	            return _vehicleIdentifier
178	        }
179	        set {
180	            lock.lock()
181	            _vehicleIdentifier = newValue
182	            lock.unlock()
183	        }
184	    }
185	    var supportedFunctions: [FunctionIdentifier]?
186	    var mockExcpetionType: CarKeyExceptionType = .None
187	    
188	    let lock = NSLock()
189	    var stateSubject: PassthroughSubject<CarKeySessionState, Never> = .init()
190	    var _state: CarKeySessionState = .NotConnected
191	    var state: CarKeySessionState {
192	        get {
193	            lock.lock()
194	            defer { lock.unlock() }
195	            return _state
196	        }
197	        set {
198	            lock.lock()
199	            guard _state != newValue else {
200	                lock.unlock()
201	                return
202	            }
203	            Log.i("Setting value to \(newValue)")
204	            _state = newValue
205	            lock.unlock()
206	            stateSubject.send(newValue)
207	        }
208	    }
209	    
210	    private var endSessionCancellable: AnyCancellable?
211	    
212	    weak var carKeyEventDelegate: CarKeySessionEventDelegate?
213	    
214	    public init(vehicleIdentifier: String, delegate: CarKeySessionEventDelegate?) {
215	        self._vehicleIdentifier = vehicleIdentifier
216	        self.carKeyEventDelegate = delegate
217	        super.init()
218	        self.state = .NotConnected
219	        self.addObserver()
220	        Log.i(tag: "carKeySession", "init,vehicleIdentifier= \(vehicleIdentifier)")
221	    }
222	    
223	    deinit {
224	        Log.i(tag: "carKeySession", "deinit,vehicleIdentifier= \(_vehicleIdentifier)")
225	        carKeyEventDelegate = nil
226	        // 直接清理 session，不触发 state setter 和 stateSubject
227	        if let session = _carKeySession {
228	            do {
229	                try session.end()
230	            } catch {
231	                Log.i(tag: "carKeySession", "deinit end session error: \(error.localizedDescription)")
232	            }
233	            _carKeySession = nil
234	        }
235	    }
236	    
237	    private func addObserver() {
238	        NotificationCenter.default.addObserver(self, selector: #selector(mockExceptionTypeChanged), name: NSNotification.Name(rawValue: "CarKeySessionMockExceptionTypeChanged"), object: nil)
239	    }
240	    
241	    @objc func mockExceptionTypeChanged(noti: Notification) {
242	        let exceptionType: Int = noti.userInfo?["exceptionType"] as? Int ?? 0
243	        self.mockExcpetionType = CarKeyExceptionType.init(rawValue: exceptionType) ?? .None
244	    }
245	    
246	    public func startCarKeySession(timeOut: TimeInterval, _ complete: @escaping ((CarKeySessionError) -> Void)) {
247	        if state == .Connecting {
248	            complete(CarKeySessionError.CarKeySessionIsConnecting)
249	            return
250	        }
251	        if state == .Disconnecting {
252	            complete(CarKeySessionError.CarKeySessionIsDisconnecting)
253	            return
254	        }
255	        self.state = .Connecting
256	        if let carKeySession = self.carKeySession {
257	            let result = refreshRealTimeCarKeySessionState(carKeySession: carKeySession)
258	            self.state = result.0
259	            complete(result.1)
260	        } else {
261	            Log.i(tag: "carKeySession", "startCarKeySession")
262	            var observeTimeOut: TimeInterval = timeOut
263	            if self.mockExcpetionType == .Block {
264	                observeTimeOut = 10000
265	            }
266	            let monitorTask = Task.detached { [weak self] in
267	                guard let self = self else {
268	                    return
269	                }
270	                try await Task.sleep(nanoseconds: UInt64((timeOut + 3) * 1_000_000_000))
271	                // 如果执行到这里，说明内层阻塞了
272	                Log.i(tag: "carKeySession", "block exception occurred！")
273	                self.carKeyEventDelegate?.reportBlockingException(data: CarKeyExceptionObj(cccVid: self.vehicleIdentifier, exceptionType: .Block, sessionError: .Block))
274	            }
275	            Log.i(tag: "carKeySession", "do carkeySession start")
276	            CarKeySessionAccesser.detachedWithTimeout(
277	                seconds: observeTimeOut,
278	                operation: { [weak self] in
279	                    guard let self = self else {
280	                        throw CarKeySessionError.Unknown
281	                    }
282	                    if self.mockExcpetionType == .Block {
283	                        try await Task.sleep(nanoseconds: UInt64(observeTimeOut * 1_000_000_000))
284	                    } else if self.mockExcpetionType == .Timeout {
285	                        try await Task.sleep(nanoseconds: UInt64((observeTimeOut + 2) * 1_000_000_000))
286	                    } else if self.mockExcpetionType == .Error {
287	                        throw CarKeySessionError.RequestTimedOut
288	                    }
289	                    return try await CarKeyRemoteControl.start(delegate: self)
290	                },
291	                onSuccess: { [weak self] result in
292	                    guard let self = self else { return }
293	                    Log.i(tag: "carKeySession", "do carkeySession end")
294	                    self.carKeySession = result
295	                    let connectState = self.refreshRealTimeCarKeySessionState(carKeySession: result)
296	                    self.state = connectState.0
297	                    complete(connectState.1)
298	                    monitorTask.cancel()
299	                    self.carKeyEventDelegate?.reportBlockingException(data: CarKeyExceptionObj(cccVid: self.vehicleIdentifier, exceptionType: .None, sessionError: .None))
300	                },
301	                onTimeout: { [weak self] in
302	                    Log.i("carKeySession", "start carkeySession timeout")
303	                    monitorTask.cancel()
304	                    complete(.TaskTimedOut)
305	                    guard let self = self else { return }
306	                    self.carKeyEventDelegate?.reportBlockingException(data: CarKeyExceptionObj(cccVid: self.vehicleIdentifier, exceptionType: .Timeout, sessionError: .TaskTimedOut))
307	                },
308	                onError: { [weak self] error in
309	                    Log.i(tag: "carKeySession", "start session error occurred: \(error.localizedDescription)")
310	                    monitorTask.cancel()
311	                    var sessionError: CarKeySessionError = .Unknown
312	                    if let carKeyError = error as? CarKeyErrorCode {
313	                        if carKeyError == .ClientInBackground {
314	                            sessionError = .ClientInBackground
315	                        } else if carKeyError == .Internal {
316	                            sessionError = .Unknown
317	                        } else if carKeyError == .VehicleNotConnected {
318	                            sessionError = .BleIsNotConnected
319	                        } else if carKeyError == .SessionNotActive {
320	                            sessionError = .SessionNotActive
321	                        }  else if carKeyError == .SecurityViolation {
322	                            sessionError = .SecurityViolation
323	                        } else if carKeyError == .RequestTimedOut {
324	                            sessionError = .RequestTimedOut
325	                        } else {
326	                            sessionError = .Unknown
327	                        }
328	                    } else {
329	                        sessionError = .Unknown
330	                    }
331	                    complete(sessionError)
332	                    guard let self = self else { return }
333	                    self.carKeyEventDelegate?.reportBlockingException(data: CarKeyExceptionObj(cccVid: self.vehicleIdentifier, exceptionType: .Error, sessionError: sessionError))
334	                }
335	            )
336	        }
337	    }
338	    
339	    func endCarKeySession(_ completion: ((CarKeySessionError) -> Void)?) {
340	        if state != CarKeySessionState.Connecting {
341	            let result = executeEndSessionOperation()
342	            completion?(result)
343	            return
344	        }
345	        self.endSessionCancellable = self.stateSubject
346	            .filter { $0 != CarKeySessionState.Connecting }
347	            .first()
348	            .sink { [weak self] newState in
349	                guard let self = self else {
350	                    completion?(.Unknown)
351	                    return
352	                }
353	                self.endSessionCancellable?.cancel()
354	                self.endSessionCancellable = nil
355	                let result = self.executeEndSessionOperation()
356	                completion?(result)
357	            }
358	    }
359	    
360	    private func executeEndSessionOperation() -> CarKeySessionError {
361	        guard let carKeySession = self.carKeySession else {
362	            Log.i(tag: "carKeySession", "car key session is nil")
363	            self.state = .NotConnected
364	            return CarKeySessionError.CarKeySessionIsNil
365	        }
366	        self.state = .Disconnecting
367	        do {
368	            Log.i(tag: "carKeySession", "end key session")
369	            try carKeySession.end()
370	            self.carKeySession = nil
371	            self.state = .NotConnected
372	            return CarKeySessionError.None
373	        } catch let error as NSError {
374	            self.carKeySession = nil
375	            self.state = .NotConnected
376	            Log.i(tag: "carKeySession", "end session error occurred: \(error.localizedDescription)")
377	            return CarKeySessionError.Unknown
378	        }
379	    }
380	    
381	    public func sendPassthroughtData(data: Data, timeOut: TimeInterval, _ complete: @escaping ((CarKeySessionError) -> Void)) {
382	        guard let carkeySession = self.carKeySession else {
383	            complete(.CarKeySessionIsNil)
384	            return
385	        }
386	        if self.vehicleIdentifier == "" {
387	            complete(.VehicleIdentifierNotFound)
388	            return
389	        }
390	        let result = self.refreshRealTimeCarKeySessionState(carKeySession: carkeySession)
391	        self.state = result.0
392	        if result.1 != .None {
393	            complete(result.1)
394	            return
395	        }
396	        CarKeySessionAccesser.detachedWithTimeout(
397	            seconds: timeOut,
398	            operation: { [weak self] in
399	                guard let self = self else {
400	                    throw CarKeySessionError.Unknown
401	                }
402	                try await carkeySession.sendPassthroughData(data, toVehicle: self.vehicleIdentifier)
403	            },
404	            onSuccess: { _ in
405	                complete(.None)
406	                Log.i(tag: "carKeySession", "Data sent successfully.")
407	            },
408	            onTimeout: {
409	                complete(.TaskTimedOut)
410	                Log.i("carKeySession", "sendPassthroughtData timeout")
411	            },
412	            onError: { [weak self] error in
413	                Log.i(tag: "carKeySession", "Failed to send data: \(error.localizedDescription)")
414	                if let carKeyError = error as? CarKeyErrorCode {
415	                    if carKeyError == .ClientInBackground {
416	                        complete(.ClientInBackground)
417	                    } else if carKeyError == .Internal {
418	                        complete(.Unknown)
419	                    } else if carKeyError == .VehicleNotConnected {
420	                        complete(.BleIsNotConnected)
421	                        self?.state = .NotConnected
422	                    } else if carKeyError == .AnotherRequestInProgress {
423	                        complete(.AnotherRequestInProgress)
424	                    } else if carKeyError == .SessionNotActive {
425	                        complete(.SessionNotActive)
426	                    } else if carKeyError == .MessageTooLong {
427	                        complete(.MessageTooLong)
428	                    } else if carKeyError == .SecurityViolation {
429	                        complete(.SecurityViolation)
430	                    } else if carKeyError == .RequestTimedOut {
431	                        complete(.RequestTimedOut)
432	                    } else {
433	                        complete(.Unknown)
434	                    }
435	                } else {
436	                    complete(.Unknown)
437	                }
438	            }
439	        )
440	    }
441	    
442	    public func getLocalKeyPollingSwitchState(complete: @escaping (CarKeyPollingSwitchState, CarKeySessionError) -> Void) {
443	        if let session = self.carKeySession {
444	            do {
445	                let on = try session.isPassiveEntryAvailable(forVehicle: self.vehicleIdentifier)
446	                Log.i(tag: "carKeySession", "get passive entry on is \(on)")
447	                if on {
448	                    complete(.On,.None)
449	                } else {
450	                    complete(.Close,.None)
451	                }
452	            } catch {
453	                Log.i(tag: "carKeySession", "get passive entry error: \(error.localizedDescription)")
454	                complete(.Unknown,.Unknown)
455	            }
456	        } else {
457	            complete(.Unknown,.SessionNotActive)
458	        }
459	    }
460	    
461	    private func refreshRealTimeCarKeySessionState(carKeySession: CarKeyRemoteControlSession) -> (CarKeySessionState, CarKeySessionError) {
462	        if let vehicleReport = getVehicleReport(carKeySession: carKeySession) {
463	            if vehicleReport.isConnected == false {
464	                if self.state != .NotConnected {
